// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section class=\"step\" id=\"s1\">\n<div class=\"step-header\">\n<div class=\"step-badge\">01</div>\n<h2>Prerequisites</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Confirming every tool is installed before writing a single line of code saves hours of cryptic errors caused by version mismatches.</div>\n<div class=\"step-body\">\n<p>You need <strong>Python 3.10 or newer</strong> and pip. Verify with:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python3 --version <span># must be 3.10+</span>\npip3 --version</pre>\n</div>\n<div>On Windows use <code>python</code> and <code>pip</code> (without the 3). On macOS/Linux always prefer <code>python3</code> to avoid accidentally calling the system Python 2.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Install <strong>pyenv</strong> to switch Python versions per-project. Run <code>pyenv install 3.12.4 &amp;&amp; pyenv local 3.12.4</code> inside your project folder.</div>\n</section>\n<section class=\"step\" id=\"s2\">\n<div class=\"step-header\">\n<div class=\"step-badge\">02</div>\n<h2>Create a virtual environment</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A virtual environment isolates this project's packages from every other Python project and the system interpreter. Without one, pip installs globally and version conflicts are inevitable.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">your project root</span>\n</div>\n<pre>mkdir mysite &amp;&amp; cd mysite\npython3 -m venv venv\nsource venv/bin/activate <span># macOS / Linux</span>\n<span># venv\\Scripts\\activate # Windows PowerShell</span></pre>\n</div>\n<div>Your terminal prompt will show <code>(venv)</code> when the environment is active. Run <code>deactivate</code> to leave it. Every <code>pip install</code> from this point forward goes into the isolated folder only.</div>\n</section>\n<section class=\"step\" id=\"s3\">\n<div class=\"step-header\">\n<div class=\"step-badge\">03</div>\n<h2>Install Django and pin versions</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Pinning exact versions in <code>requirements.txt</code> guarantees reproducible installs across developer machines, CI pipelines, and the production server.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install django\npip freeze &gt; requirements.txt <span># lock all versions immediately</span>\npython -m django --version <span># should print 5.x</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Re-run <code>pip freeze &gt; requirements.txt</code> every time you add a new package. On a fresh machine or server, restore everything with <code>pip install -r requirements.txt</code>.</div>\n</section>\n<section class=\"step\" id=\"s4\">\n<div class=\"step-header\">\n<div class=\"step-badge\">04</div>\n<h2>Create the project and app</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django separates the <em>project</em> (global configuration) from <em>apps</em> (feature modules). For a single-page site, one app called <code>pages</code> is the right abstraction \u2014 it owns your view, URL, and templates.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">inside mysite/</span>\n</div>\n<pre>django-admin startproject core . <span># dot = no redundant wrapper folder</span>\npython manage.py startapp pages</pre>\n</div>\n<div>Using a dot after the project name places <code>manage.py</code> directly in <code>mysite/</code> rather than inside a second nested folder of the same name.</div>\n</section>\n<section class=\"step\" id=\"s5\">\n<div class=\"step-header\">\n<div class=\"step-badge\">05</div>\n<h2>Understand the full project structure</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Knowing what every file does prevents editing the wrong one and makes error messages immediately meaningful. The layout below is what you should have \u2014 and what we build toward.</div>\n<div class=\"tree\">\n<span>mysite/</span>\n \u251c\u2500\u2500 <span>core/</span> <span># project package \u2014 settings, root URLs</span>\n \u2502 \u251c\u2500\u2500 <span>settings.py</span> <span># all configuration lives here</span>\n \u2502 \u251c\u2500\u2500 <span>urls.py</span> <span># root URL dispatcher</span>\n \u2502 \u251c\u2500\u2500 <span>asgi.py</span> <span># async server gateway (used by some hosts)</span>\n \u2502 \u2514\u2500\u2500 <span>wsgi.py</span> <span># WSGI entry point (Gunicorn uses this)</span>\n \u251c\u2500\u2500 <span>pages/</span> <span># your single-page app</span>\n \u2502 \u251c\u2500\u2500 <span>views.py</span>\n \u2502 \u251c\u2500\u2500 <span>urls.py</span> <span># create this yourself</span>\n \u2502 \u251c\u2500\u2500 <span>apps.py</span>\n \u2502 \u2514\u2500\u2500 <span>templates/</span>\n \u2502 \u2514\u2500\u2500 <span>pages/</span> <span># namespaced template folder</span>\n \u2502 \u251c\u2500\u2500 <span>base.html</span> <span># shell inherited by all pages</span>\n \u2502 \u251c\u2500\u2500 <span>index.html</span> <span># the single page content</span>\n \u2502 \u2514\u2500\u2500 <span>partials/</span> <span># reusable snippets (nav, footer, etc.)</span>\n \u2502 \u251c\u2500\u2500 <span>_nav.html</span>\n \u2502 \u2514\u2500\u2500 <span>_footer.html</span>\n \u251c\u2500\u2500 <span>static/</span> <span># your source static files (commit these)</span>\n \u2502 \u251c\u2500\u2500 <span>css/</span>\n \u2502 \u2502 \u2514\u2500\u2500 <span>main.css</span>\n \u2502 \u2514\u2500\u2500 <span>js/</span>\n \u2502 \u2514\u2500\u2500 <span>main.js</span>\n \u251c\u2500\u2500 <span>staticfiles/</span> <span># collectstatic output (never commit)</span>\n \u251c\u2500\u2500 <span>venv/</span> <span># virtual env (never commit)</span>\n \u251c\u2500\u2500 <span>.env</span> <span># secret variables (never commit)</span>\n \u251c\u2500\u2500 <span>.gitignore</span>\n \u251c\u2500\u2500 <span>manage.py</span>\n \u2514\u2500\u2500 <span>requirements.txt</span>\n</div>\n<div>The double-folder pattern for templates \u2014 <code>pages/templates/pages/</code> \u2014 prevents name collisions when multiple apps each have an <code>index.html</code>. Django searches all apps for templates and takes the first match, so namespacing is essential.</div>\n</section>\n<section class=\"step\" id=\"s6\">\n<div class=\"step-header\">\n<div class=\"step-badge\">06</div>\n<h2>Register the app in settings</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django only discovers your app's models, templates, and management commands after you list it in <code>INSTALLED_APPS</code>. Forgetting this is the single most common first-time mistake.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py</span>\n</div>\n<pre>INSTALLED_APPS = [\n <span>\"django.contrib.admin\"</span>,\n <span>\"django.contrib.auth\"</span>,\n <span>\"django.contrib.contenttypes\"</span>,\n <span>\"django.contrib.sessions\"</span>,\n <span>\"django.contrib.messages\"</span>,\n <span>\"django.contrib.staticfiles\"</span>,\n <span>\"pages\"</span>, <span># \u2190 add your app here</span>\n]</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Use the AppConfig dotted path (<code>\"pages.apps.PagesConfig\"</code>) instead of just <code>\"pages\"</code> \u2014 this is cleaner and enables Django signals to auto-connect when you add them later.</div>\n</section>\n<section class=\"step\" id=\"s7\">\n<div class=\"step-header\">\n<div class=\"step-badge\">07</div>\n<h2>base.html \u2014 the shell every page inherits</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Template inheritance is Django's superpower for avoiding repeated HTML. <code>base.html</code> contains the <code>&lt;head&gt;</code>, navigation, and footer once. Every other page just fills in named <code>{% block %}</code> regions.</div>\n<div class=\"step-body\">\n<p>Create the file at <code>pages/templates/pages/base.html</code>. Here is the full production-ready version with every block and tag explained inline:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">pages/templates/pages/base.html</span>\n</div>\n<pre><span>&lt;!DOCTYPE html&gt;</span>\n<span>&lt;html</span> <span>lang</span>=<span>\"en\"</span><span>&gt;</span>\n<span>&lt;head&gt;</span>\n <span>&lt;!-- Character encoding \u2014 must be first in &lt;head&gt; --&gt;</span>\n <span>&lt;meta</span> <span>charset</span>=<span>\"UTF-8\"</span><span>/&gt;</span>\n\n <span>&lt;!-- Responsive viewport \u2014 required for mobile --&gt;</span>\n <span>&lt;meta</span> <span>name</span>=<span>\"viewport\"</span> <span>content</span>=<span>\"width=device-width, initial-scale=1.0\"</span><span>/&gt;</span>\n\n <span>&lt;!-- SEO: child templates override this block --&gt;</span>\n <span>&lt;title&gt;</span>{% block title %}My Site{% endblock %} | My Site<span>&lt;/title&gt;</span>\n\n <span>&lt;!-- Open Graph meta \u2014 social sharing previews --&gt;</span>\n <span>&lt;meta</span> <span>property</span>=<span>\"og:title\"</span> <span>content</span>=<span>\"{% block og_title %}My Site{% endblock %}\"</span><span>/&gt;</span>\n <span>&lt;meta</span> <span>property</span>=<span>\"og:description\"</span> <span>content</span>=<span>\"{% block og_desc %}A Django site{% endblock %}\"</span><span>/&gt;</span>\n <span>&lt;meta</span> <span>property</span>=<span>\"og:type\"</span> <span>content</span>=<span>\"website\"</span><span>/&gt;</span>\n\n <span>&lt;!-- Security headers via meta (add real headers in Nginx too) --&gt;</span>\n <span>&lt;meta</span> <span>http-equiv</span>=<span>\"X-Content-Type-Options\"</span> <span>content</span>=<span>\"nosniff\"</span><span>/&gt;</span>\n\n <span>&lt;!-- Load the {% static %} tag before using it --&gt;</span>\n {% load static %}\n\n <span>&lt;!-- Google Fonts \u2014 preconnect first for speed --&gt;</span>\n <span>&lt;link</span> <span>rel</span>=<span>\"preconnect\"</span> <span>href</span>=<span>\"https://fonts.googleapis.com\"</span><span>/&gt;</span>\n <span>&lt;link</span> <span>href</span>=<span>\"https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600&amp;display=swap\"</span>\n <span>rel</span>=<span>\"stylesheet\"</span><span>/&gt;</span>\n\n <span>&lt;!-- Your main stylesheet \u2014 {% static %} resolves to /static/css/main.css --&gt;</span>\n <span>&lt;link</span> <span>rel</span>=<span>\"stylesheet\"</span> <span>href</span>=<span>\"{% static 'css/main.css' %}\"</span><span>/&gt;</span>\n\n <span>&lt;!-- Child templates can inject extra &lt;link&gt; or &lt;style&gt; tags here --&gt;</span>\n {% block extra_css %}{% endblock %}\n<span>&lt;/head&gt;</span>\n<span>&lt;body&gt;</span>\n\n <span>&lt;!-- Skip-to-content link \u2014 accessibility best practice --&gt;</span>\n <span>&lt;a</span> <span>class</span>=<span>\"skip-link\"</span> <span>href</span>=<span>\"#main-content\"</span><span>&gt;</span>Skip to content<span>&lt;/a&gt;</span>\n\n <span>&lt;!-- Navigation partial \u2014 kept in its own file for maintainability --&gt;</span>\n {% include \"pages/partials/_nav.html\" %}\n\n <span>&lt;!-- Django messages (flash messages for form success/error feedback) --&gt;</span>\n {% if messages %}\n <span>&lt;div</span> <span>class</span>=<span>\"messages\"</span><span>&gt;</span>\n {% for message in messages %}\n <span>&lt;div</span> <span>class</span>=<span>\"message message--{{ message.tags }}\"</span><span>&gt;</span>{{ message }}<span>&lt;/div&gt;</span>\n {% endfor %}\n <span>&lt;/div&gt;</span>\n {% endif %}\n\n <span>&lt;!-- Main content region \u2014 child templates override this block --&gt;</span>\n <span>&lt;main</span> <span>id</span>=<span>\"main-content\"</span><span>&gt;</span>\n {% block content %}{% endblock %}\n <span>&lt;/main&gt;</span>\n\n <span>&lt;!-- Footer partial --&gt;</span>\n {% include \"pages/partials/_footer.html\" %}\n\n <span>&lt;!-- Main JS file \u2014 loaded at the bottom so DOM is ready --&gt;</span>\n <span>&lt;script</span> <span>src</span>=<span>\"{% static 'js/main.js' %}\"</span> <span>defer</span><span>&gt;&lt;/script&gt;</span>\n\n <span>&lt;!-- Child templates can inject extra scripts here --&gt;</span>\n {% block extra_js %}{% endblock %}\n\n<span>&lt;/body&gt;</span>\n<span>&lt;/html&gt;</span></pre>\n</div>\n<div>\n<div class=\"explain-card\">\n<h4>{% load static %}</h4>\n<p>Must appear before any <code>{% static '...' %}</code> call. Loads the tag library that resolves static file URLs \u2014 it reads <code>STATIC_URL</code> from settings.</p>\n</div>\n<div class=\"explain-card\">\n<h4>{% block title %}</h4>\n<p>A named region child templates can override. If a child provides no <code>{% block title %}</code>, the fallback text \"My Site\" is used. Always end with <code>{% endblock %}</code>.</p>\n</div>\n<div class=\"explain-card\">\n<h4>{% include \"...\" %}</h4>\n<p>Pulls in another template file at that exact position. The included file shares the same template context (variables). Use for nav, footer, and other repeated fragments.</p>\n</div>\n<div class=\"explain-card\">\n<h4>{% block extra_css %}</h4>\n<p>An empty block child templates can fill with page-specific styles or a <code>&lt;link&gt;</code> to an additional CSS file, without touching the base layout.</p>\n</div>\n</div>\n<div class=\"tone-danger\"><strong>Warning:</strong> Never put <code>{% load static %}</code> inside an <code>{% include %}</code>d partial \u2014 load it at the top of the base template instead. Partials inherit loads from the parent.</div>\n</section>\n<section class=\"step\" id=\"s8\">\n<div class=\"step-header\">\n<div class=\"step-badge\">08</div>\n<h2>index.html \u2014 the single page content template</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>This is the only content template for a single-page site. It extends <code>base.html</code> and fills in the blocks. Every variable passed from the view is available here.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">pages/templates/pages/index.html</span>\n</div>\n<pre><span>&lt;!-- Inherit everything from base.html --&gt;</span>\n{% extends \"pages/base.html\" %}\n\n<span>&lt;!-- Override the &lt;title&gt; block --&gt;</span>\n{% block title %}Welcome{% endblock %}\n\n<span>&lt;!-- Fill Open Graph tags for social sharing --&gt;</span>\n{% block og_title %}Welcome to My Site{% endblock %}\n{% block og_desc %}{{ page.description }}{% endblock %}\n\n<span>&lt;!-- Main content \u2014 this is the only block you MUST fill --&gt;</span>\n{% block content %}\n\n<span>&lt;section</span> <span>class</span>=<span>\"hero\"</span><span>&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"container\"</span><span>&gt;</span>\n <span>&lt;h1&gt;</span>{{ page.headline }}<span>&lt;/h1&gt;</span>\n <span>&lt;p&gt;</span>{{ page.subheadline }}<span>&lt;/p&gt;</span>\n <span>&lt;a</span> <span>href</span>=<span>\"#contact\"</span> <span>class</span>=<span>\"btn btn--primary\"</span><span>&gt;</span>Get in touch<span>&lt;/a&gt;</span>\n <span>&lt;/div&gt;</span>\n<span>&lt;/section&gt;</span>\n\n<span>&lt;section</span> <span>class</span>=<span>\"features\"</span> <span>id</span>=<span>\"features\"</span><span>&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"container\"</span><span>&gt;</span>\n <span>&lt;h2&gt;</span>What we do<span>&lt;/h2&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"grid grid--3\"</span><span>&gt;</span>\n {% for feature in features %}\n <span>&lt;div</span> <span>class</span>=<span>\"card\"</span><span>&gt;</span>\n <span>&lt;h3&gt;</span>{{ feature.title }}<span>&lt;/h3&gt;</span>\n <span>&lt;p&gt;</span>{{ feature.body }}<span>&lt;/p&gt;</span>\n <span>&lt;/div&gt;</span>\n {% endfor %}\n <span>&lt;/div&gt;</span>\n <span>&lt;/div&gt;</span>\n<span>&lt;/section&gt;</span>\n\n<span>&lt;section</span> <span>class</span>=<span>\"contact\"</span> <span>id</span>=<span>\"contact\"</span><span>&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"container\"</span><span>&gt;</span>\n <span>&lt;h2&gt;</span>Get in touch<span>&lt;/h2&gt;</span>\n <span>&lt;!-- CSRF token is required on every POST form --&gt;</span>\n <span>&lt;form</span> <span>method</span>=<span>\"post\"</span> <span>novalidate</span><span>&gt;</span>\n {% csrf_token %}\n {{ form.as_p }}\n <span>&lt;button</span> <span>type</span>=<span>\"submit\"</span> <span>class</span>=<span>\"btn btn--primary\"</span><span>&gt;</span>Send<span>&lt;/button&gt;</span>\n <span>&lt;/form&gt;</span>\n <span>&lt;/div&gt;</span>\n<span>&lt;/section&gt;</span>\n\n{% endblock %}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> For a truly static single page with no database, you can hardcode content directly in the template and skip the context variables entirely. Add them later only when content needs to be editable.</div>\n</section>\n<section class=\"step\" id=\"s9\">\n<div class=\"step-header\">\n<div class=\"step-badge\">09</div>\n<h2>Partials \u2014 nav and footer</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Partials (included template fragments) keep base.html short and each component maintainable. The convention is to prefix partial file names with an underscore.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">pages/templates/pages/partials/_nav.html</span>\n</div>\n<pre><span>&lt;header</span> <span>class</span>=<span>\"site-header\"</span><span>&gt;</span>\n <span>&lt;nav</span> <span>class</span>=<span>\"nav container\"</span> <span>aria-label</span>=<span>\"Main navigation\"</span><span>&gt;</span>\n <span>&lt;!-- {% url 'pages:home' %} uses named URL \u2014 never hardcode paths --&gt;</span>\n <span>&lt;a</span> <span>href</span>=<span>\"{% url 'pages:home' %}\"</span> <span>class</span>=<span>\"nav__logo\"</span><span>&gt;</span>MyBrand<span>&lt;/a&gt;</span>\n <span>&lt;ul</span> <span>class</span>=<span>\"nav__links\"</span> <span>role</span>=<span>\"list\"</span><span>&gt;</span>\n <span>&lt;li&gt;&lt;a</span> <span>href</span>=<span>\"#features\"</span><span>&gt;</span>Features<span>&lt;/a&gt;&lt;/li&gt;</span>\n <span>&lt;li&gt;&lt;a</span> <span>href</span>=<span>\"#contact\"</span><span>&gt;</span>Contact<span>&lt;/a&gt;&lt;/li&gt;</span>\n <span>&lt;/ul&gt;</span>\n <span>&lt;!-- Mobile hamburger toggle \u2014 JS in main.js handles this --&gt;</span>\n <span>&lt;button</span> <span>class</span>=<span>\"nav__burger\"</span> <span>aria-label</span>=<span>\"Open menu\"</span> <span>aria-expanded</span>=<span>\"false\"</span><span>&gt;</span>\n <span>&lt;span&gt;&lt;/span&gt;&lt;span&gt;&lt;/span&gt;&lt;span&gt;&lt;/span&gt;</span>\n <span>&lt;/button&gt;</span>\n <span>&lt;/nav&gt;</span>\n<span>&lt;/header&gt;</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">pages/templates/pages/partials/_footer.html</span>\n</div>\n<pre><span>&lt;footer</span> <span>class</span>=<span>\"site-footer\"</span><span>&gt;</span>\n <span>&lt;div</span> <span>class</span>=<span>\"container\"</span><span>&gt;</span>\n <span>&lt;!-- now() requires {% load tz %} or use Python's date in the view context --&gt;</span>\n <span>&lt;p&gt;</span>&amp;copy; {% now \"Y\" %} MyBrand. All rights reserved.<span>&lt;/p&gt;</span>\n <span>&lt;/div&gt;</span>\n<span>&lt;/footer&gt;</span></pre>\n</div>\n<div>The <code>{% now \"Y\" %}</code> tag outputs the current year \u2014 no more hardcoded copyright years that go stale. It is built-in; no extra load required.</div>\n</section>\n<section class=\"step\" id=\"s10\">\n<div class=\"step-header\">\n<div class=\"step-badge\">10</div>\n<h2>CSS \u2014 production-ready main.css</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A well-structured CSS file using custom properties (variables) is easy to theme and maintain. Writing a mobile-first baseline avoids the common pitfall of a responsive site that was desktop-only first.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/main.css</span>\n</div>\n<pre><span>/* \u2500\u2500 Reset \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n*,*::before,*::after { box-sizing: border-box; margin: 0; padding: 0; }\nimg, video { max-width: 100%; display: block; }\nul[role=\"list\"] { list-style: none; } <span>/* only reset lists with role */</span>\n\n<span>/* \u2500\u2500 Design tokens (change these, not individual rules) */</span>\n:root {\n --color-bg: #ffffff;\n --color-surface: #f4f6f9;\n --color-text: #111827;\n --color-muted: #6b7280;\n --color-accent: #2563eb;\n --color-accent-h: #1d4ed8; <span>/* accent hover */</span>\n --color-border: #e5e7eb;\n --font-sans: 'Inter', system-ui, sans-serif;\n --font-size-base: 1rem;\n --line-height: 1.7;\n --radius: 8px;\n --shadow-sm: 0 1px 3px rgba(0,0,0,.08);\n --shadow-md: 0 4px 16px rgba(0,0,0,.12);\n --container-w: 1120px;\n --section-gap: 5rem;\n}\n\n<span>/* \u2500\u2500 Base \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\nhtml { scroll-behavior: smooth; }\nbody { font-family: var(--font-sans); font-size: var(--font-size-base);\n line-height: var(--line-height); color: var(--color-text);\n background: var(--color-bg); }\na { color: var(--color-accent); text-decoration: none; }\na:hover{ color: var(--color-accent-h); text-decoration: underline; }\nh1,h2,h3 { line-height: 1.2; }\n\n<span>/* \u2500\u2500 Skip link (accessibility) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.skip-link {\n position: absolute; top: -99px; left: 8px; z-index: 9999;\n background: var(--color-accent); color: #fff;\n padding: 8px 16px; border-radius: var(--radius);\n transition: top .15s;\n}\n.skip-link:focus { top: 8px; }\n\n<span>/* \u2500\u2500 Container \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.container {\n width: 100%; max-width: var(--container-w);\n margin-inline: auto; padding-inline: 1.25rem;\n}\n\n<span>/* \u2500\u2500 Navigation \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.site-header {\n position: sticky; top: 0; z-index: 100;\n background: rgba(255,255,255,.9);\n backdrop-filter: blur(10px);\n border-bottom: 1px solid var(--color-border);\n}\n.nav {\n display: flex; align-items: center;\n justify-content: space-between;\n height: 64px; gap: 2rem;\n}\n.nav__logo { font-weight: 600; font-size: 1.1rem; color: var(--color-text); }\n.nav__links { display: flex; gap: 1.5rem; }\n.nav__links a { color: var(--color-muted); font-size: .9rem; font-weight: 500; }\n.nav__links a:hover { color: var(--color-text); text-decoration: none; }\n.nav__burger { display: none; flex-direction: column; gap: 5px;\n background: none; border: none; cursor: pointer; padding: 4px; }\n.nav__burger span { display: block; width: 22px; height: 2px;\n background: var(--color-text); border-radius: 2px;\n transition: transform .25s, opacity .25s; }\n\n<span>/* \u2500\u2500 Buttons \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.btn {\n display: inline-flex; align-items: center; gap: .5rem;\n padding: .65rem 1.4rem; border-radius: var(--radius);\n font-weight: 500; font-size: .9rem; cursor: pointer;\n border: 2px solid transparent; transition: background .15s, color .15s, border-color .15s;\n}\n.btn--primary {\n background: var(--color-accent); color: #fff;\n}\n.btn--primary:hover { background: var(--color-accent-h); color: #fff; text-decoration: none; }\n.btn--outline {\n background: transparent; color: var(--color-accent);\n border-color: var(--color-accent);\n}\n.btn--outline:hover { background: var(--color-accent); color: #fff; text-decoration: none; }\n\n<span>/* \u2500\u2500 Grid \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.grid { display: grid; gap: 1.5rem; }\n.grid--2 { grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); }\n.grid--3 { grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); }\n\n<span>/* \u2500\u2500 Card \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.card {\n background: var(--color-surface);\n border: 1px solid var(--color-border);\n border-radius: var(--radius);\n padding: 1.5rem;\n box-shadow: var(--shadow-sm);\n transition: box-shadow .2s, transform .2s;\n}\n.card:hover { box-shadow: var(--shadow-md); transform: translateY(-2px); }\n.card h3 { font-size: 1rem; margin-bottom: .5rem; }\n.card p { font-size: .9rem; color: var(--color-muted); }\n\n<span>/* \u2500\u2500 Hero section \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.hero {\n padding: var(--section-gap) 0;\n background: linear-gradient(135deg, var(--color-surface) 0%, #fff 60%);\n text-align: center;\n}\n.hero h1 { font-size: clamp(2rem, 5vw, 3.5rem); margin-bottom: 1rem; }\n.hero p { font-size: 1.15rem; color: var(--color-muted); margin-bottom: 2rem; }\n\n<span>/* \u2500\u2500 Sections \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.features, .contact { padding: var(--section-gap) 0; }\n.features h2, .contact h2 {\n font-size: 1.8rem; text-align: center; margin-bottom: 2.5rem;\n}\n\n<span>/* \u2500\u2500 Contact form \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.contact form { max-width: 520px; margin-inline: auto; display: grid; gap: 1rem; }\n.contact input, .contact textarea, .contact select {\n width: 100%; padding: .65rem 1rem;\n border: 1px solid var(--color-border); border-radius: var(--radius);\n font-family: inherit; font-size: .95rem;\n background: var(--color-surface);\n transition: border-color .15s, box-shadow .15s;\n}\n.contact input:focus, .contact textarea:focus {\n outline: none;\n border-color: var(--color-accent);\n box-shadow: 0 0 0 3px rgba(37,99,235,.15);\n}\n.contact textarea { resize: vertical; min-height: 120px; }\n\n<span>/* \u2500\u2500 Flash messages \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.messages { position: fixed; top: 72px; right: 1rem; z-index: 200; display: grid; gap: .5rem; }\n.message { padding: .75rem 1.25rem; border-radius: var(--radius);\n font-size: .9rem; box-shadow: var(--shadow-md); }\n.message--success { background: #d1fae5; color: #065f46; border: 1px solid #a7f3d0; }\n.message--error { background: #fee2e2; color: #991b1b; border: 1px solid #fecaca; }\n\n<span>/* \u2500\u2500 Footer \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n.site-footer {\n border-top: 1px solid var(--color-border);\n padding: 2rem 0; font-size: .875rem; color: var(--color-muted);\n text-align: center;\n}\n\n<span>/* \u2500\u2500 Mobile responsive \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n@media (max-width: 640px) {\n .nav__links { display: none; flex-direction: column;\n position: fixed; inset: 64px 0 0 0;\n background: var(--color-bg);\n padding: 2rem; gap: 1rem; }\n .nav__links.open { display: flex; }\n .nav__burger { display: flex; }\n :root { --section-gap: 3rem; }\n}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> CSS custom properties (<code>--variable: value</code>) make theming trivial. Swap out the <code>:root</code> colour and font tokens to completely rebrand the site without touching any other rule.</div>\n</section>\n<section class=\"step\" id=\"s11\">\n<div class=\"step-header\">\n<div class=\"step-badge\">11</div>\n<h2>JavaScript \u2014 main.js</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>A minimal, dependency-free JS file handles mobile navigation, smooth scroll behaviour, and form UX. No build tool required for a single-page site at this scale.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">JavaScript</span>\n<span class=\"code-file\">static/js/main.js</span>\n</div>\n<pre><span>/* \u2500\u2500 Mobile navigation toggle \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n<span>const</span> burger = document.querySelector(<span>'.nav__burger'</span>);\n<span>const</span> links = document.querySelector(<span>'.nav__links'</span>);\n\n<span>if</span> (burger &amp;&amp; links) {\n burger.addEventListener(<span>'click'</span>, () =&gt; {\n <span>const</span> open = links.classList.toggle(<span>'open'</span>);\n burger.setAttribute(<span>'aria-expanded'</span>, open);\n burger.setAttribute(<span>'aria-label'</span>, open ? <span>'Close menu'</span> : <span>'Open menu'</span>);\n });\n\n <span>// Close nav when a link is clicked (SPA-style smoothness)</span>\n links.querySelectorAll(<span>'a'</span>).forEach(a =&gt; {\n a.addEventListener(<span>'click'</span>, () =&gt; {\n links.classList.remove(<span>'open'</span>);\n burger.setAttribute(<span>'aria-expanded'</span>, <span>'false'</span>);\n });\n });\n}\n\n<span>/* \u2500\u2500 Sticky nav background on scroll \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\n<span>const</span> header = document.querySelector(<span>'.site-header'</span>);\n<span>if</span> (header) {\n window.addEventListener(<span>'scroll'</span>, () =&gt; {\n header.classList.toggle(<span>'scrolled'</span>, window.scrollY &gt; 10);\n }, { passive: <span>true</span> });\n}\n\n<span>/* \u2500\u2500 Auto-dismiss flash messages after 5 s \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */</span>\ndocument.querySelectorAll(<span>'.message'</span>).forEach(msg =&gt; {\n setTimeout(() =&gt; {\n msg.style.transition = <span>'opacity .4s'</span>;\n msg.style.opacity = <span>'0'</span>;\n setTimeout(() =&gt; msg.remove(), 400);\n }, 5000);\n});\n\n<span>/* \u2500\u2500 Active nav link on scroll (Intersection Observer) \u2500 */</span>\n<span>const</span> sections = document.querySelectorAll(<span>'section[id]'</span>);\n<span>const</span> navLinks = document.querySelectorAll(<span>'.nav__links a[href^=\"#\"]'</span>);\n\n<span>const</span> obs = <span>new</span> IntersectionObserver(entries =&gt; {\n entries.forEach(e =&gt; {\n <span>if</span> (e.isIntersecting) {\n navLinks.forEach(l =&gt; l.classList.remove(<span>'active'</span>));\n document.querySelector(`.nav__links a[href=\"#${e.target.id}\"]`)\n ?.classList.add(<span>'active'</span>);\n }\n });\n}, { rootMargin: <span>'-30% 0px -60% 0px'</span> });\n\nsections.forEach(s =&gt; obs.observe(s));</pre>\n</div>\n<div>The <code>defer</code> attribute on the <code>&lt;script&gt;</code> tag in <code>base.html</code> means this file is parsed after the DOM \u2014 so no <code>DOMContentLoaded</code> wrapper is needed and it does not block page rendering.</div>\n</section>\n<section class=\"step\" id=\"s12\">\n<div class=\"step-header\">\n<div class=\"step-badge\">12</div>\n<h2>Static file settings</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's static file system separates your source CSS/JS from the collected production output. The two directories serve completely different purposes and must never be confused.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py</span>\n</div>\n<pre><span># URL prefix Django uses to serve static files in development</span>\nSTATIC_URL = <span>\"/static/\"</span>\n\n<span># Where collectstatic writes all files for production serving</span>\nSTATIC_ROOT = BASE_DIR / <span>\"staticfiles\"</span>\n\n<span># Extra locations Django's staticfiles finder searches</span>\nSTATICFILES_DIRS = [BASE_DIR / <span>\"static\"</span>]\n\n<span># User-uploaded file handling (not used in a purely static site)</span>\nMEDIA_URL = <span>\"/media/\"</span>\nMEDIA_ROOT = BASE_DIR / <span>\"media\"</span></pre>\n</div>\n<div>\n<div class=\"explain-card\">\n<h4>STATIC_URL</h4>\n<p>The URL prefix browsers request. <code>{% static 'css/main.css' %}</code> becomes <code>/static/css/main.css</code>. Never serve <code>STATIC_ROOT</code> in development \u2014 Django handles it automatically.</p>\n</div>\n<div class=\"explain-card\">\n<h4>STATIC_ROOT</h4>\n<p>The destination folder for <code>collectstatic</code>. This is what Nginx or WhiteNoise serves in production. Add <code>staticfiles/</code> to your <code>.gitignore</code> \u2014 never commit it.</p>\n</div>\n<div class=\"explain-card\">\n<h4>STATICFILES_DIRS</h4>\n<p>A list of additional directories (beyond each app's <code>static/</code> subfolder) where Django looks for static files. Your project-level <code>static/</code> folder lives here.</p>\n</div>\n<div class=\"explain-card\">\n<h4>collectstatic</h4>\n<p>Run <code>python manage.py collectstatic --noinput</code> before every deploy. It copies all files from every app and from <code>STATICFILES_DIRS</code> into <code>STATIC_ROOT</code>.</p>\n</div>\n</div>\n<div class=\"tone-danger\"><strong>Warning:</strong> With <code>DEBUG=True</code>, Django's dev server serves static files automatically. With <code>DEBUG=False</code> it does not \u2014 you must use WhiteNoise or Nginx. Forgetting this is the most common deployment mystery.</div>\n</section>\n<section class=\"step\" id=\"s13\">\n<div class=\"step-header\">\n<div class=\"step-badge\">13</div>\n<h2>View function</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>For a single-page site, one view function handles both GET (render the page) and POST (process the contact form). Keeping this logic together makes the flow easy to follow.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">pages/views.py</span>\n</div>\n<pre><span>from</span> django.shortcuts <span>import</span> render, redirect\n<span>from</span> django.contrib <span>import</span> messages\n<span>from</span> .forms <span>import</span> ContactForm\n\n\n<span>def</span> <span>home</span>(request):\n <span># Static content \u2014 swap these for database objects later if needed</span>\n page = {\n <span>\"headline\"</span>: <span>\"Build something great.\"</span>,\n <span>\"subheadline\"</span>: <span>\"We help businesses move fast with elegant software.\"</span>,\n <span>\"description\"</span>: <span>\"A Django single-page site \u2014 fast, secure, maintainable.\"</span>,\n }\n features = [\n {<span>\"title\"</span>: <span>\"Fast\"</span>, <span>\"body\"</span>: <span>\"Optimised queries, WhiteNoise static serving.\"</span>},\n {<span>\"title\"</span>: <span>\"Secure\"</span>, <span>\"body\"</span>: <span>\"CSRF, XSS, HSTS, and Content-Security-Policy out of the box.\"</span>},\n {<span>\"title\"</span>: <span>\"Deployable\"</span>, <span>\"body\"</span>: <span>\"Gunicorn + Nginx or Railway in under 10 minutes.\"</span>},\n ]\n\n <span>if</span> request.method == <span>\"POST\"</span>:\n form = <span>ContactForm</span>(request.POST)\n <span>if</span> form.is_valid():\n form.save() <span># or send_mail() \u2014 your choice</span>\n messages.<span>success</span>(request, <span>\"Message sent! We'll be in touch soon.\"</span>)\n <span>return</span> <span>redirect</span>(<span>\"pages:home\"</span>) <span># PRG pattern prevents duplicate submissions</span>\n <span>else</span>:\n form = <span>ContactForm</span>()\n\n <span>return</span> <span>render</span>(request, <span>\"pages/index.html\"</span>, {\n <span>\"page\"</span>: page,\n <span>\"features\"</span>: features,\n <span>\"form\"</span>: form,\n })</pre>\n</div>\n<div class=\"tone-tip\"><strong>PRG Pattern:</strong> After a successful POST, always <code>redirect()</code> instead of rendering directly. This prevents the browser from re-submitting the form when the user hits refresh \u2014 a very common bug.</div>\n</section>\n<section class=\"step\" id=\"s14\">\n<div class=\"step-header\">\n<div class=\"step-badge\">14</div>\n<h2>URL wiring</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Named URLs (<code>name=</code>) decouple your templates and views from actual URL paths. Rename a URL once in <code>urls.py</code> and every <code>{% url %}</code> and <code>redirect()</code> using the name updates automatically.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">pages/urls.py (create this file)</span>\n</div>\n<pre><span>from</span> django.urls <span>import</span> path\n<span>from</span> . <span>import</span> views\n\napp_name = <span>\"pages\"</span> <span># namespace: use as 'pages:home'</span>\n\nurlpatterns = [\n path(<span>\"\"</span>, views.home, name=<span>\"home\"</span>),\n]</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/urls.py</span>\n</div>\n<pre><span>from</span> django.contrib <span>import</span> admin\n<span>from</span> django.urls <span>import</span> path, include\n<span>from</span> django.conf <span>import</span> settings\n<span>from</span> django.conf.urls.static <span>import</span> static\n\nurlpatterns = [\n path(<span>\"admin/\"</span>, admin.site.urls),\n path(<span>\"\"</span>, include(<span>\"pages.urls\"</span>, namespace=<span>\"pages\"</span>)),\n]\n\n<span># Serve user-uploaded media files during development only</span>\n<span>if</span> settings.DEBUG:\n urlpatterns += static(settings.MEDIA_URL, document_root=settings.MEDIA_ROOT)</pre>\n</div>\n</section>\n<section class=\"step\" id=\"s15\">\n<div class=\"step-header\">\n<div class=\"step-badge\">15</div>\n<h2>Context data and forms</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's form system validates input server-side automatically, prevents XSS, and surfaces error messages to the template \u2014 all without writing validation logic manually.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">pages/forms.py (create this file)</span>\n</div>\n<pre><span>from</span> django <span>import</span> forms\n\n\n<span>class</span> <span>ContactForm</span>(forms.Form):\n name = forms.<span>CharField</span>(max_length=<span>100</span>)\n email = forms.<span>EmailField</span>()\n message = forms.<span>CharField</span>(widget=forms.<span>Textarea</span>(attrs={<span>\"rows\"</span>: <span>5</span>}))\n\n <span>def</span> <span>clean_message</span>(self):\n <span># Custom validation: reject very short messages</span>\n msg = self.cleaned_data[<span>\"message\"</span>]\n <span>if</span> len(msg) &lt; 20:\n <span>raise</span> forms.<span>ValidationError</span>(<span>\"Please write at least 20 characters.\"</span>)\n <span>return</span> msg\n\n <span>def</span> <span>save</span>(self):\n <span># Replace with send_mail() or save to a ContactMessage model</span>\n <span>from</span> django.core.mail <span>import</span> send_mail\n d = self.cleaned_data\n <span>send_mail</span>(\n subject=<span>f</span>(<span>\"Contact from {d['name']}\"</span>),\n message=d[<span>\"message\"</span>],\n from_email=d[<span>\"email\"</span>],\n recipient_list=[<span>\"hello@example.com\"</span>],\n )</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> To send email in production, set <code>EMAIL_BACKEND = \"django.core.mail.backends.smtp.EmailBackend\"</code> and configure <code>EMAIL_HOST</code>, <code>EMAIL_PORT</code>, <code>EMAIL_HOST_USER</code>, and <code>EMAIL_HOST_PASSWORD</code> via environment variables. Use SendGrid, Mailgun, or Amazon SES for reliable delivery.</div>\n</section>\n<section class=\"step\" id=\"s16\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">16</div>\n<h2>Split settings for production</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Running <code>DEBUG=True</code> in production exposes your full stack trace and settings to any error page. A settings split keeps development convenience separate from hardened production values and prevents shipping secrets.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install python-decouple\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py (top section \u2014 replace hardcoded values)</span>\n</div>\n<pre><span>from</span> pathlib <span>import</span> Path\n<span>from</span> decouple <span>import</span> config\n\nBASE_DIR = Path(__file__).resolve().parent.parent\n\n<span># Secret key must NEVER be hardcoded \u2014 read from .env</span>\nSECRET_KEY = config(<span>\"SECRET_KEY\"</span>)\n\n<span># False in production \u2014 True only during local development</span>\nDEBUG = config(<span>\"DEBUG\"</span>, default=<span>False</span>, cast=bool)\n\n<span># Comma-separated list in .env e.g. \"yourdomain.com,www.yourdomain.com\"</span>\nALLOWED_HOSTS = config(<span>\"ALLOWED_HOSTS\"</span>, cast=<span>lambda</span> v: [h.strip() <span>for</span> h <span>in</span> v.split(<span>\",\"</span>)])\n\n<span># HTTPS security headers \u2014 set True in production</span>\nSECURE_SSL_REDIRECT = config(<span>\"SECURE_SSL\"</span>, default=<span>False</span>, cast=bool)\nSESSION_COOKIE_SECURE = <span>not</span> DEBUG\nCSRF_COOKIE_SECURE = <span>not</span> DEBUG\nSECURE_HSTS_SECONDS = <span>31536000</span> <span># 1 year once HTTPS is confirmed working</span>\nSECURE_CONTENT_TYPE_NOSNIFF = <span>True</span>\nX_FRAME_OPTIONS = <span>\"DENY\"</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.env (never commit \u2014 add to .gitignore immediately)</span>\n</div>\n<pre>SECRET_KEY=replace-with-50-random-chars-generated-by-django\nDEBUG=False\nALLOWED_HOSTS=yourdomain.com,www.yourdomain.com\nDATABASE_URL=postgres://user:password@localhost:5432/mysite\nSECURE_SSL=True</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">.gitignore</span>\n</div>\n<pre>venv/\n.env\nstaticfiles/\nmedia/\n__pycache__/\n*.pyc\n*.pyo\ndb.sqlite3\n.DS_Store</pre>\n</div>\n<div class=\"tone-danger\"><strong>Warning:</strong> Generate a new SECRET_KEY with <code>python -c \"from django.core.management.utils import get_random_secret_key; print(get_random_secret_key())\"</code>. Never reuse the one from the initial <code>startproject</code> scaffold.</div>\n</section>\n<section class=\"step\" id=\"s17\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">17</div>\n<h2>Switch to PostgreSQL</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>SQLite is single-writer and file-based. PostgreSQL handles concurrent connections, full-text search, JSON columns, and the row-level locking that production traffic demands.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install psycopg2-binary dj-database-url\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py</span>\n</div>\n<pre><span>import</span> dj_database_url\n\nDATABASES = {\n <span>\"default\"</span>: dj_database_url.<span>config</span>(\n default=<span>config</span>(<span>\"DATABASE_URL\"</span>),\n conn_max_age=<span>600</span>, <span># keep connections alive for 10 min (connection pooling)</span>\n ssl_require=<span>not</span> DEBUG, <span># enforce SSL in production</span>\n )\n}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> For local development keep a <code>DATABASE_URL=sqlite:///db.sqlite3</code> in your <code>.env</code> and only switch to Postgres on the server. The code is identical \u2014 only the URL changes.</div>\n</section>\n<section class=\"step\" id=\"s18\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">18</div>\n<h2>WhiteNoise \u2014 serve static files without Nginx</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>WhiteNoise lets Gunicorn serve compressed, cache-busted static files directly \u2014 no Nginx configuration needed for static assets on platforms like Railway, Render, or Heroku.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install whitenoise[brotli]\npip freeze &gt; requirements.txt</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py \u2014 MIDDLEWARE (order matters)</span>\n</div>\n<pre>MIDDLEWARE = [\n <span>\"django.middleware.security.SecurityMiddleware\"</span>,\n <span>\"whitenoise.middleware.WhiteNoiseMiddleware\"</span>, <span># \u2190 must be second</span>\n <span>\"django.contrib.sessions.middleware.SessionMiddleware\"</span>,\n <span>\"django.middleware.common.CommonMiddleware\"</span>,\n <span>\"django.middleware.csrf.CsrfViewMiddleware\"</span>,\n <span>\"django.contrib.auth.middleware.AuthenticationMiddleware\"</span>,\n <span>\"django.contrib.messages.middleware.MessageMiddleware\"</span>,\n <span>\"django.middleware.clickjacking.XFrameOptionsMiddleware\"</span>,\n]\n\n<span># WhiteNoise compression and cache-busting via content hash in filenames</span>\nSTORAGES = {\n <span>\"staticfiles\"</span>: {\n <span>\"BACKEND\"</span>: <span>\"whitenoise.storage.CompressedManifestStaticFilesStorage\"</span>,\n },\n}</pre>\n</div>\n<div><code>CompressedManifestStaticFilesStorage</code> appends a content hash to every filename (e.g. <code>main.abc123.css</code>), so browsers cache assets indefinitely and instantly receive new versions after a deploy.</div>\n</section>\n<section class=\"step\" id=\"s19\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">19</div>\n<h2>Gunicorn + Nginx (VPS deployment)</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's dev server is single-threaded and unsafe for public traffic. Gunicorn runs multiple worker processes; Nginx sits in front to handle TLS termination and can also serve static files if you skip WhiteNoise.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>pip install gunicorn\npip freeze &gt; requirements.txt\n\n<span># Collect static assets before starting</span>\npython manage.py collectstatic --noinput\npython manage.py migrate\n\n<span># Start \u2014 4 workers handle ~200 concurrent requests on a 2-core VPS</span>\ngunicorn core.wsgi:application \\\n --workers 4 \\\n --bind 0.0.0.0:8000 \\\n --timeout 120 \\\n --access-logfile - \\\n --error-logfile -</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">/etc/nginx/sites-available/mysite</span>\n</div>\n<pre>server {\n listen 80;\n server_name yourdomain.com www.yourdomain.com;\n return 301 https://$host$request_uri; # Redirect all HTTP to HTTPS\n}\n\nserver {\n listen 443 ssl http2;\n server_name yourdomain.com www.yourdomain.com;\n\n ssl_certificate /etc/letsencrypt/live/yourdomain.com/fullchain.pem;\n ssl_certificate_key /etc/letsencrypt/live/yourdomain.com/privkey.pem;\n ssl_protocols TLSv1.2 TLSv1.3;\n\n # Serve static files directly \u2014 faster than proxying to Gunicorn\n location /static/ {\n alias /path/to/mysite/staticfiles/;\n expires 1y;\n add_header Cache-Control \"public, immutable\";\n }\n\n location /media/ {\n alias /path/to/mysite/media/;\n }\n\n # Proxy everything else to Gunicorn\n location / {\n proxy_pass http://127.0.0.1:8000;\n proxy_set_header Host $host;\n proxy_set_header X-Real-IP $remote_addr;\n proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n proxy_set_header X-Forwarded-Proto $scheme;\n proxy_read_timeout 120s;\n }\n}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Free TLS:</strong> Run <code>sudo certbot --nginx -d yourdomain.com -d www.yourdomain.com</code> after installing Certbot. It provisions a Let's Encrypt certificate and patches your Nginx config automatically.</div>\n</section>\n<section class=\"step\" id=\"s20\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">20</div>\n<h2>Cloud platform deployment (Railway / Render)</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Managed platforms handle TLS, scaling, and server maintenance automatically. For a single-page site with modest traffic, Railway or Render is simpler and often cheaper than running your own VPS.</div>\n<div class=\"step-body\">\n<p>Create a <strong>Procfile</strong> and a <strong>runtime.txt</strong> in the project root:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">Procfile</span>\n</div>\n<pre>web: python manage.py migrate --noinput &amp;&amp; python manage.py collectstatic --noinput &amp;&amp; gunicorn core.wsgi:application --workers 2 --bind 0.0.0.0:$PORT</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Text</span>\n<span class=\"code-file\">runtime.txt</span>\n</div>\n<pre>python-3.12.4</pre>\n</div>\n<div class=\"step-body\">\n<p>On Railway: connect your GitHub repo, add your <code>.env</code> variables as Railway environment variables, and deploy. On Render: create a new Web Service, set the build command to <code>pip install -r requirements.txt</code> and the start command to the Procfile web entry.</p>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> Both platforms inject a <code>PORT</code> environment variable. The <code>--bind 0.0.0.0:$PORT</code> flag ensures Gunicorn listens on the correct port. Django's <code>ALLOWED_HOSTS</code> must include your <code>.railway.app</code> or <code>.onrender.com</code> domain.</div>\n</section>\n<section class=\"step\" id=\"s21\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">21</div>\n<h2>Pre-deploy checklist</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's built-in deployment check catches the most common security misconfigurations automatically. Run it before every deploy, not just the first one.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n</div>\n<pre>python manage.py check --deploy <span># must return zero errors</span>\npython manage.py migrate\npython manage.py collectstatic --noinput</pre>\n</div>\n<ul class=\"checklist\">\n<li><code>DEBUG = False</code> in production \u2014 confirmed via <code>--deploy</code> check</li>\n<li><code>SECRET_KEY</code> is a 50+ character random string and is not in source control</li>\n<li><code>ALLOWED_HOSTS</code> lists only your actual domain(s) \u2014 not <code>*</code></li>\n<li>HTTPS enforced: <code>SECURE_SSL_REDIRECT = True</code> and a valid TLS certificate</li>\n<li><code>SESSION_COOKIE_SECURE = True</code> and <code>CSRF_COOKIE_SECURE = True</code></li>\n<li><code>SECURE_HSTS_SECONDS = 31536000</code> \u2014 only set after confirming HTTPS works</li>\n<li><code>DATABASE_URL</code> points to PostgreSQL, not SQLite</li>\n<li><code>STATIC_ROOT</code> populated via <code>collectstatic</code> \u2014 WhiteNoise or Nginx serves it</li>\n<li><code>venv/</code>, <code>.env</code>, and <code>staticfiles/</code> are in <code>.gitignore</code></li>\n<li>Error monitoring configured \u2014 install <code>sentry-sdk</code> and add <code>sentry_sdk.init(dsn=...)</code></li>\n<li>Database backups configured \u2014 use managed Postgres or set up pg_dump cron job</li>\n</ul>\n</section>\n<section id=\"cheatsheet\">\n<h2>Django Cheat Sheet</h2>\n<p class=\"section-sub\">Quick-reference commands, template tags, security settings, and tips for single-page Django sites.</p>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span>\u2301</span><h3>Management Commands</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>startproject name .</code><span>Scaffold project in current directory</span></div>\n<div class=\"cheat-item\"><code>startapp name</code><span>Create a new app</span></div>\n<div class=\"cheat-item\"><code>runserver</code><span>Dev server on port 8000</span></div>\n<div class=\"cheat-item\"><code>makemigrations</code><span>Generate migrations from model changes</span></div>\n<div class=\"cheat-item\"><code>migrate</code><span>Apply pending migrations</span></div>\n<div class=\"cheat-item\"><code>createsuperuser</code><span>Create admin account interactively</span></div>\n<div class=\"cheat-item\"><code>collectstatic --noinput</code><span>Gather all static files into STATIC_ROOT</span></div>\n<div class=\"cheat-item\"><code>check --deploy</code><span>Run security checks for production</span></div>\n<div class=\"cheat-item\"><code>shell</code><span>Python REPL with Django fully loaded</span></div>\n<div class=\"cheat-item\"><code>showmigrations</code><span>List all migrations and their status</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Template Tags</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{% extends \"base.html\" %}</code><span>Inherit from a parent template</span></div>\n<div class=\"cheat-item\"><code>{% block name %}{% endblock %}</code><span>Define an overrideable region</span></div>\n<div class=\"cheat-item\"><code>{% include \"partial.html\" %}</code><span>Insert another template inline</span></div>\n<div class=\"cheat-item\"><code>{% load static %}</code><span>Enable static file tags</span></div>\n<div class=\"cheat-item\"><code>{% static 'css/main.css' %}</code><span>Resolve a static file URL</span></div>\n<div class=\"cheat-item\"><code>{% url 'pages:home' %}</code><span>Reverse URL by namespaced name</span></div>\n<div class=\"cheat-item\"><code>{% csrf_token %}</code><span>Required inside every POST form</span></div>\n<div class=\"cheat-item\"><code>{% now \"Y\" %}</code><span>Current year \u2014 great for copyright</span></div>\n<div class=\"cheat-item\"><code>{% if %}{% elif %}{% else %}</code><span>Conditionals</span></div>\n<div class=\"cheat-item\"><code>{% for x in list %}{% empty %}</code><span>Loop with fallback for empty lists</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Template Filters</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{{ val|truncatewords:20 }}</code><span>Trim to 20 words with ellipsis</span></div>\n<div class=\"cheat-item\"><code>{{ val|date:\"F j, Y\" }}</code><span>Format a datetime nicely</span></div>\n<div class=\"cheat-item\"><code>{{ val|default:\"N/A\" }}</code><span>Fallback if value is falsy</span></div>\n<div class=\"cheat-item\"><code>{{ val|linebreaks }}</code><span>Convert newlines to &lt;p&gt; tags</span></div>\n<div class=\"cheat-item\"><code>{{ val|striptags }}</code><span>Remove HTML tags from value</span></div>\n<div class=\"cheat-item\"><code>{{ val|safe }}</code><span>Mark as safe HTML \u2014 only for trusted content</span></div>\n<div class=\"cheat-item\"><code>{{ val|lower }}</code><span>Lowercase the string</span></div>\n<div class=\"cheat-item\"><code>{{ val|length }}</code><span>Count items in list or string length</span></div>\n<div class=\"cheat-item\"><code>{{ val|add:10 }}</code><span>Add a number to the value</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Security Settings</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>DEBUG = False</code><span>Never True in production</span></div>\n<div class=\"cheat-item\"><code>SECURE_SSL_REDIRECT</code><span>Force HTTP \u2192 HTTPS (True in prod)</span></div>\n<div class=\"cheat-item\"><code>SESSION_COOKIE_SECURE</code><span>Session cookie only over HTTPS</span></div>\n<div class=\"cheat-item\"><code>CSRF_COOKIE_SECURE</code><span>CSRF cookie only over HTTPS</span></div>\n<div class=\"cheat-item\"><code>SECURE_HSTS_SECONDS</code><span>31536000 = 1 year HSTS header</span></div>\n<div class=\"cheat-item\"><code>X_FRAME_OPTIONS = \"DENY\"</code><span>Block clickjacking in iframes</span></div>\n<div class=\"cheat-item\"><code>SECURE_CONTENT_TYPE_NOSNIFF</code><span>Prevent MIME-type sniffing</span></div>\n<div class=\"cheat-item\"><code>ALLOWED_HOSTS</code><span>List exact domains \u2014 never use *</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>View Patterns</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>render(request, \"t.html\", {})</code><span>Return rendered template response</span></div>\n<div class=\"cheat-item\"><code>redirect(\"pages:home\")</code><span>HTTP 302 redirect by URL name</span></div>\n<div class=\"cheat-item\"><code>get_object_or_404(Model, pk=1)</code><span>Return object or raise 404</span></div>\n<div class=\"cheat-item\"><code>messages.success(request, \"...\")</code><span>Flash message \u2014 shown once</span></div>\n<div class=\"cheat-item\"><code>request.method == \"POST\"</code><span>Check for form submission</span></div>\n<div class=\"cheat-item\"><code>form.is_valid()</code><span>Validate and populate cleaned_data</span></div>\n<div class=\"cheat-item\"><code>JsonResponse({\"ok\": True})</code><span>Return JSON for AJAX endpoints</span></div>\n<div class=\"cheat-item\"><code>@login_required</code><span>Decorator: redirect if not logged in</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Production Tips</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>whitenoise</code><span>Serve static files from Gunicorn \u2014 no Nginx needed</span></div>\n<div class=\"cheat-item\"><code>dj-database-url</code><span>Parse DATABASE_URL env variable cleanly</span></div>\n<div class=\"cheat-item\"><code>python-decouple</code><span>Read .env variables with type casting</span></div>\n<div class=\"cheat-item\"><code>gunicorn --workers 4</code><span>2\u00d7 CPU cores = good starting point</span></div>\n<div class=\"cheat-item\"><code>conn_max_age=600</code><span>Persistent DB connections \u2014 reduces latency</span></div>\n<div class=\"cheat-item\"><code>STORAGES CompressedManifest</code><span>Brotli/gzip + cache-busting hashes</span></div>\n<div class=\"cheat-item\"><code>sentry-sdk</code><span>Real-time error tracking in production</span></div>\n<div class=\"cheat-item\"><code>certbot --nginx</code><span>Free HTTPS certificate from Let's Encrypt</span></div>\n</div>\n</div>\n</div>\n</section>";

